histrix.customScript:
        	window.setTimeout(function(){
        		$('[campo="observacion_control"] > div').css({'border':'0px'});
			}, 1000);


    		$('td[campo="conforme"] input:checkbox:checked').closest('tr').css({'background-color':'greenyellow'});

			$('td[campo="observacion_control"] input', $('td[campo="no_conforme"] input:checkbox:checked').closest('tr')).show();

			//$('td[campo="observacion_control"] input', $('td[campo="conforme"] input:checkbox:checked').closest('tr')).show();

        	// refresh update check
			$('[campo] :input:checkbox').change(function(){
					var tr = $(this).closest('tr');

					$('td[campo="update"] input', tr).val('1');
			});
			$('[campo="controlcausal_id"]').change(function(){
					var tr = $(this).closest('tr');

					$('td[campo="update"] input', tr).val('1');
			});
			$('[campo="legajo_personal"]').change(function(){
					var tr = $(this).closest('tr');

					$('td[campo="update"] input', tr).val('1');
			});

        	$('td[campo="conforme"] input:checkbox').change(function(){
        		var tr = $(this).closest('tr');

        		$('[name="observacion_control"]', tr).show();
				$('[name="observacion_control"]', tr).each(function(){
				    	if ($(this).val() == '') 
						$(this).hide();
				});

/*        		$('[campo="controlcausal_id"]', tr).show();
				$('[campo="controlcausal_id"]', tr).each(function(){
				    	if ($(this).val() == '') 
						$(this).hide();
				});*/
        		if ($(this).prop('checked')){

	        		$(tr).css({'background-color':'greenyellow'});

    	    		var $noconf = $('td[campo="no_conforme"] input:checkbox', tr).prop('checked', !$(this).prop('checked'));

					try {
					    $noconf.checkboxradio("refresh");
					} catch (err){$('[name="controlcausal_id"]', tr)
				    	// no es movil
					}

        		} else {
        			tr.css({'background-color':'transparent'});
        		}
        	});


        	$('td[campo="no_conforme"] input:checkbox').change(function(){
        		var tr = $(this).closest('tr');


        		if ($(this).prop('checked')){
        			$('[name="observacion_control"]', tr).show();
//				$('[campo="controlcausal_id"]', tr).show();


	        		tr.css({'background-color':'transparent'});
	        		var $conf = $('td[campo="conforme"] input:checkbox', tr).prop('checked', !$(this).prop('checked'));

				try {
				    $conf.checkboxradio("refresh");
				} catch (err){
				    // no es movil
				}


        		} else {
        			$('td[campo="observacion_control"] input', tr).hide();
//				$('td[campo="controlcausal_id"]', tr).hide();
        		}
        	});        	



        	$('td[campo="no_aplica"] input:checkbox').change(function(){
        		var tr = $(this).closest('tr');
        		if ($(this).prop('checked')){
        		//	$('[name="observacion_control"]', tr).hide();


	        		tr.css({'background-color':'#ddd',  'text-decoration':'line-through'});
	        		var $conf = $('td[campo="conforme"] input:checkbox, td[campo="no_conforme"] input:checkbox', tr).prop('checked', !$(this).prop('checked')).prop('disabled',true);
				try {
				    $conf.checkboxradio("refresh");
				} catch (err){
				    // no es movil
				}


				$('td[campo="conforme"] input:checkbox, td[campo="no_conforme"] input:checkbox', tr).closest('td').css({'background-color':'transparent'});
        		} else {
	        		tr.css({'background-color':'inherit',  'text-decoration':'none'});

	        		var $conf = $('td[campo="conforme"] input:checkbox, td[campo="no_conforme"] input:checkbox', tr).prop('checked', $(this).prop('checked')).prop('disabled',false).checkboxradio("refresh");

				try {
				    $conf.checkboxradio("refresh");
				} catch (err){
				    // no es movil
				}

				tr.css({'background-color':'transparent' ,  'text-decoration':'none'});
        		//	$('td[campo="observacion_control"] input', tr).show();
        		}
        	});        	


			$('[name="observacion_control"]').each(function(){
				if ($(this).val() == '') 
					$(this).hide();
			});
/*			$('[campo="controlcausal_id"]').each(function(){
				if ($(this).val() == '') 
					$(this).hide();
			});
*/
